define nofpclass(zero) <3 x float> @partially_defined_0_splat_to_poison() {
; CHECK-LABEL: define nofpclass(zero) <3 x float> @partially_defined_0_splat_to_poison() {
; CHECK-NEXT:    ret <3 x float> poison
  ret <3 x float> <float 0.000000e+00, float 0.000000e+00, float poison>
}

tests.source_program:
define nofpclass(zero) <3 x float> @partially_defined_0_splat_to_poison() {
  ret <3 x float> <float 0.000000e+00, float 0.000000e+00, float poison>
}

define nofpclass(nan ninf nzero nsub nnorm) float @ret_nofpclass_nan_negatives__select_clamp_pos_to_zero(float %x) {
  %is.gt.zero = fcmp ogt float %x, 0.000000e+00
  %select = select i1 %is.gt.zero, float 0.000000e+00, float %x
  ret float %select
}
